get_config_chr <- function(x, default = NULL) {
  opt <- getOption(paste0("cli.", tolower(x)))
  if (!is.null(opt)) {
    stopifnot(is_string(opt))
    return(opt)
  }

  env <- Sys.getenv(paste0("R_CLI_", toupper(x)), NA_character_)
  if (!is.na(env)) return(env)

  default
}
